SELECT * FROM dev_device

    is_deleted = 0

        AND serial_port_id = #{serialPortId}


        AND serial_port_id IN

            #{pid}



        AND model_id = #{modelId}


        AND status = #{status}


        AND (name LIKE CONCAT('%', #{keyword}, '%')
         OR code LIKE CONCAT('%', #{keyword}, '%'))


ORDER BY id ASC
